import { Logger } from '@nestjs/common';
import _ from 'lodash';
import { EntityManager, ILike, In } from 'typeorm';

import { Coded, Persistence } from '@/app/common/decorators';
import { QueryUtil } from '@/app/common/utils/query.util';
import { ItemSearchDtoValidated } from '@/app/models/dto/item.dto';
import { Item } from '@/app/models/item';
import { BasePersistence } from '@/app/persistence/base-persistence';

/**
 * Commonize the internal functionality of transactions in services about sessions.
 */
@Coded('PITM')
@Persistence()
export class ItemsPersistence extends BasePersistence {
  private readonly logger = new Logger(ItemsPersistence.name);

  constructor() {
    super();
  }

  static readonly ERROR_CODES = {};

  get EC() {
    return ItemsPersistence.ERROR_CODES;
  }

  async searchItems(
    t: EntityManager,
    conditions: ItemSearchDtoValidated,
  ): Promise<{
    itemIds: string[];
    total: number;
  }> {
    const orderBy = {
      id: 'id',
      name: 'name',
      created_at: 'createdAt',
    }[conditions.orderBy];
    // Use queryBuilder or divide multiple queries for more complex search.
    const [items, total] = await t.findAndCount(Item, {
      select: {
        id: true,
      },
      where: {
        name: conditions.keyword ? ILike(`%${conditions.keyword}%`) : undefined,
        isPaid: conditions.isPaid ?? undefined,
        isSubscription: conditions.isSubscription ?? undefined,
      },
      // relations: {
      // },
      order: {
        [orderBy[conditions.orderBy] ?? 'id']: conditions.isOrderDesc
          ? 'DESC'
          : 'ASC',
      },
      ...(!_.isNil(conditions.pageSize)
        ? {
            skip: conditions.pageSize * (conditions.page ?? 0),
            take: conditions.pageSize,
          }
        : {}),
    });

    return {
      itemIds: _.map(items, (x) => x.id),
      total,
    };
  }

  async getItems(t: EntityManager, itemIds: string[]) {
    const items = await t.find(Item, {
      where: {
        id: In(itemIds),
      },
      relations: {
        aiCoachs: true,
        balls: true,
        subscriptions: true,
      },
    });

    return QueryUtil.sortByOriginalIds(items, itemIds);
  }
}

