import {
  Column,
  Entity,
  OneToMany,
  PrimaryGeneratedColumn,
  UpdateDateColumn,
} from 'typeorm';

import { Subscription } from './subscription';

@Entity('subscription_groups', { schema: 'public' })
export class SubscriptionGroup {
  @PrimaryGeneratedColumn('uuid', { name: 'id' })
  id: string;

  @Column('varchar', {
    name: 'stripe_price_table_id',
    nullable: true,
    length: 255,
  })
  stripePriceTableId: string | null;

  @Column('integer', {
    name: 'apple_subscription_group_id',
    nullable: true,
  })
  appleSubscriptionGroupId: number | null;

  @Column('boolean', { name: 'is_active', default: true })
  isActive: boolean;

  @Column('varchar', {
    name: 'team_type',
    length: 31,
    default: 'multiple',
  })
  teamType: string;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @UpdateDateColumn({
    name: 'updated_at',
    type: 'timestamp with time zone',
  })
  updatedAt: Date;

  @OneToMany(
    () => Subscription,
    (subscription) => subscription.subscriptionGroup,
  )
  subscriptions: Subscription[];
}

