import { INestApplication } from '@nestjs/common';
import { Test } from '@nestjs/testing';
import _ from 'lodash';
import request from 'supertest';

import { DataUtil } from '@/app/common/utils/data.util';
import { AppModule } from '@/app/modules/app.module';
import { users } from '@/database/seeding/generators/data/users';
import { DataUtil as TestDataUtil } from '@/database/seeding/generators/utils/data.util';

import { TestUtil } from '@test/app/test-utils/test.util';
import { itemsResultForSearch1, itemsResultForSearch2 } from '@test/data/items';

const userFinder = TestDataUtil.getFinder(users);

describe('Items', () => {
  let app: INestApplication;

  const superUserId = userFinder.getByTag('spr_adm1-team_1').id;

  beforeAll(async () => {
    const moduleRef = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();
    app = moduleRef.createNestApplication();
    await app.init();
  });

  it(`List raw items`, () => {
    return request(app.getHttpServer())
      .post(`/api/items/search`)
      .set({
        Authorization: superUserId,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        keyword: null,
        isPaid: null,
        orderBy: 'id',
        isOrderDesc: false,
      })
      .expect(201)
      .expect((res) =>
        expect(
          DataUtil.omitDeep(res.body, ['updatedAt', 'createdAt']),
        ).toMatchObject(itemsResultForSearch1),
      );
  });

  it(`Search raw items`, () => {
    return request(app.getHttpServer())
      .post(`/api/items/search`)
      .set({
        Authorization: superUserId,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        keyword: 'dummy keyword',
        isPaid: null,
        orderBy: 'id',
        isOrderDesc: false,
      })
      .expect(201)
      .expect((res) =>
        expect(
          DataUtil.omitDeep(res.body, ['updatedAt', 'createdAt']),
        ).toMatchObject(itemsResultForSearch2),
      );
  });

  afterAll(async () => {
    await app.close();
  });
});

