import { Logger } from '@nestjs/common';
import _ from 'lodash';
import { EntityManager, ILike, In } from 'typeorm';

import { Coded, Persistence } from '@/app/common/decorators';
import { QueryUtil } from '@/app/common/utils/query.util';
import { SubscriptionSearchDtoValidated } from '@/app/models/dto/subscription.dto';
import { Plan } from '@/app/models/plan';
import { Subscription } from '@/app/models/subscription';
import { BasePersistence } from '@/app/persistence/base-persistence';

/**
 * Commonize the internal functionality of transactions in services about sessions.
 */
@Coded('PSCN')
@Persistence()
export class SubscriptionsPersistence extends BasePersistence {
  private readonly logger = new Logger(SubscriptionsPersistence.name);

  constructor() {
    super();
  }

  static readonly ERROR_CODES = {};

  get EC() {
    return SubscriptionsPersistence.ERROR_CODES;
  }

  async searchSubscriptions(
    t: EntityManager,
    conditions: SubscriptionSearchDtoValidated,
  ): Promise<{
    subscriptionIds: string[];
    total: number;
  }> {
    const orderBy = {
      id: 'id',
      name: 'name',
      created_at: 'createdAt',
    }[conditions.orderBy];
    // Use queryBuilder or divide multiple queries for more complex search.
    const [subscriptions, total] = await t.findAndCount(Subscription, {
      select: {
        id: true,
      },
      where: {
        name: conditions.keyword ? ILike(`%${conditions.keyword}%`) : undefined,
        isPaid: conditions.isPaid ?? undefined,
      },
